sql:
SELECT primary_language
FROM ethnic_groups
WHERE ethnic_group_id > 5;

SELECT eg.ethnic_group_id, eg.ethnic_group_name, egc.total_cases, egc.total_hospitalized
FROM ethnic_groups eg
JOIN ethnic_group_cases egc ON eg.ethnic_group_id = egc.ethnic_group_id;

SELECT DISTINCT department
FROM users
ORDER BY department ASC;

external_knowledge:
- "Mighty rivers" metaphorically refers to ethnic groups with a high number of cases;
- "Flowing with more than 50,000 cases" represents the condition where the total cases are greater than 50,000;
- "Ocean" symbolizes the total cases, and the percentage of all cases reflects the portion each ethnic group represents of the total;
- "Breadth of the river in descending order" represents ordering by the percentage of all cases in descending order.

- "waves of health protection" is a metaphor for the number of vaccinations;
- "tempests of sickness" is a metaphor for the number of hospitalizations;
- "the day the leaves began to fall" refers to October 1, 2022, symbolizing the change in weather and season.

sql:
SELECT case_status, COUNT(*) as number_of_cases
FROM covid_cases
GROUP BY case_status;

SELECT case_id, age, location
FROM covid_cases
WHERE case_status = 'recovered' AND gender = 'female';

external_knowledge:
- "storm clouds" metaphorically refers to the total number of cases;
- "lightning strikes" metaphorically refers to the number of hospitalizations within those cases;
- "sails on the horizon" metaphorically represents active cases;
- "umbrella" is a metaphor for the vaccine type (the kind of protection they have).

sql:
SELECT AVG(population_size) AS average_population_size
FROM ethnic_groups
WHERE population_size > (SELECT AVG(population_size) FROM ethnic_groups);

SELECT c.case_id, c.age, c.gender
FROM covid_cases c
INNER JOIN case_vaccination_link vl ON c.case_id = vl.case_id;

SELECT case_id, hospitalization_id
FROM hospitalizations
WHERE discharge_date IS NOT NULL;

SELECT vaccination_id, data_source_id, total_vaccinated
FROM vaccination_data
WHERE vaccination_id = 0;

SELECT eg.ethnic_group_name, c.case_status, c.age, c.gender
FROM ethnic_groups eg
JOIN covid_cases c ON eg.ethnic_group_id = c.ethnic_group_id;

SELECT total_cases
FROM ethnic_group_cases
WHERE ethnic_group_id = (
  SELECT ethnic_group_id
  FROM ethnic_group_vaccinations
  WHERE total_vaccinated = (
    SELECT MAX(total_vaccinated) 
    FROM ethnic_group_vaccinations
  )
);

SELECT e.ethnic_group_name, ed.age_distribution, ed.gender_distribution
FROM ethnic_groups e
INNER JOIN ethnic_group_data ed ON e.ethnic_group_id = ed.ethnic_group_id;
